import { MakeLogicType, actions, kea, path, reducers } from 'kea'


export type LivePersonDrillDownBreakdownType = 'country' | 'city' | 'device' | 'browser'

export interface LivePersonDrillDownSelection {
    breakdownType: LivePersonDrillDownBreakdownType
    breakdownValue: string
    breakdownLabel: string
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface livePersonDrillDownDrawerLogicValues {
    currentSelection: LivePersonDrillDownSelection | null;
}

// Generated by kea-typegen. Update if you're an agent, ignore if you're human.
export interface livePersonDrillDownDrawerLogicActions {
    closeDrillDown: () => {
        value: true;
    };
    openDrillDown: (selection: LivePersonDrillDownSelection) => LivePersonDrillDownSelection;
}

export type livePersonDrillDownDrawerLogicType = MakeLogicType<livePersonDrillDownDrawerLogicValues, livePersonDrillDownDrawerLogicActions>;

export const livePersonDrillDownDrawerLogic = kea<livePersonDrillDownDrawerLogicType>([
    path(['scenes', 'webAnalytics', 'livePersonDrillDownDrawerLogic']),
    actions({
        openDrillDown: (selection: LivePersonDrillDownSelection) => selection,
        closeDrillDown: true,
    }),
    reducers({
        currentSelection: [
            null as LivePersonDrillDownSelection | null,
            {
                openDrillDown: (_, payload) => payload,
                closeDrillDown: () => null,
            },
        ],
    }),
])
